const lib = global.get('lib');
if (!lib || !lib.telemetry || typeof lib.telemetry.handleTelemetryMessage !== 'function') {
  node.status({ fill: 'red', shape: 'ring', text: 'telemetry API missing' });
  return [null, null, { payload: { error: 'TELEMETRY_API_MISSING' } }];
}

const telemetry = lib.telemetry;
const incoming = msg.payload && typeof msg.payload === 'object' && !Array.isArray(msg.payload)
  ? { ...msg, ...msg.payload }
  : msg;
const equipmentId = incoming.equipmentId || incoming.instance?.equipmentId || incoming._reader?.equipmentId || msg.equipmentId;
const stateKey = equipmentId ? `telemetryState:${equipmentId}` : null;
const state = stateKey ? (flow.get(stateKey) || telemetry.createTelemetryRuntimeState()) : telemetry.createTelemetryRuntimeState();

if (incoming.error && !equipmentId) {
  node.status({ fill: 'yellow', shape: 'ring', text: 'modbus transport error' });
  return [null, null, { payload: { error: incoming.error, source: 'modbus', incoming } }];
}

if (!equipmentId) {
  node.status({ fill: 'red', shape: 'ring', text: 'equipment missing' });
  return [null, null, { payload: { error: 'EQUIPMENT_ID_MISSING', incoming } }];
}

const asNodeRedMsg = (value) => {
  if (value == null) return null;
  if (typeof value === 'object' && !Array.isArray(value) && Object.prototype.hasOwnProperty.call(value, 'payload')) {
    return value;
  }
  return { payload: value };
};

const decorate = (value) => {
  const out = asNodeRedMsg(value);
  if (!out) return null;
  out.equipmentId = out.equipmentId || equipmentId;
  out.serverKey = out.serverKey || incoming.serverKey || incoming.instance?.serverKey || equipmentId;
  return out;
};

const envCfg = {
  CompilerMaxQty: 120,
  CompilerMaxSpan: 80,
  CompilerMaxHole: 4,
  PollFastMs: 250,
  PollNormalMs: 1000,
  PollSlowMs: 5000,
  MAX_IN_FLIGHT: 8,
  REQUEST_TIMEOUT_MS: 1500,
  MODBUS_ZERO_BASED: false,
  JITTER_MS: 0,
  RESPECT_TAG_CLAMP: true,
  SCALE_CLAMP_DEFAULT: false,
  SKIP_EMPTY_SAMPLES: false
};

try {
  const result = telemetry.handleTelemetryMessage(
    incoming,
    envCfg,
    state,
    (o1, o2, o3) => node.send([decorate(o1), decorate(o2), decorate(o3)])
  );

  if (stateKey) {
    flow.set(stateKey, result.state);
  }

  const statusText = `${equipmentId}:${incoming.cmd || (incoming._reader ? 'reply' : 'start')}`;
  node.status({ fill: 'green', shape: 'dot', text: statusText });

  return [decorate(result.out1), decorate(result.out2), decorate(result.out3)];
} catch (err) {
  node.status({ fill: 'red', shape: 'ring', text: `${equipmentId}:runtime threw` });
  return [null, null, { payload: { error: String(err), equipmentId } }];
}

const incoming = Array.isArray(msg.payload) ? msg.payload : [];
const inferEquipment = () => {
  if (msg.equipmentId) return msg.equipmentId;
  if (msg.payload && typeof msg.payload === 'object' && msg.payload.equipment) return msg.payload.equipment;
  for (const sample of incoming) {
    if (sample && typeof sample.tagID === 'string' && sample.tagID.includes('.')) {
      return sample.tagID.split('.')[0];
    }
  }
  return 'UNKNOWN';
};

const equipmentName = inferEquipment();
const legacyStore = global.get('NEW_telemetry') || {};
const modernStore = global.get('telemetry') || {};
const store = { ...legacyStore, ...modernStore };
const current = Array.isArray(store[equipmentName]) ? store[equipmentName] : [];
const byTag = {};

const toIsoTs = (value) => {
  if (typeof value === 'string' && value.trim()) {
    const parsed = new Date(value);
    if (!Number.isNaN(parsed.getTime())) return parsed.toISOString();
  }
  if (typeof value === 'number' && Number.isFinite(value)) {
    return new Date(value).toISOString();
  }
  return new Date().toISOString();
};

const normalizeFlag = (value) => {
  if (value === true) return 'Yes';
  if (value === false) return 'No';
  if (typeof value === 'string') {
    const norm = value.trim().toLowerCase();
    if (norm === 'yes' || norm === 'true') return 'Yes';
    if (norm === 'no' || norm === 'false' || norm === '') return 'No';
  }
  return 'No';
};

for (const sample of current) {
  if (sample && sample.tagID) byTag[sample.tagID] = sample;
}

for (const sample of incoming) {
  if (!sample || !sample.tagID) continue;
  const tagID = sample.tagID.includes('.')
    ? sample.tagID
    : `${equipmentName}.${sample.tagID}`;

  byTag[tagID] = {
    tagID,
    value: sample.value,
    timestamp: toIsoTs(sample.timestamp),
    alarm: normalizeFlag(sample.alarm),
    supportingTag: normalizeFlag(sample.supportingTag)
  };

  if (sample.enumLabel !== undefined) byTag[tagID].enumLabel = sample.enumLabel;
  if (sample.activeBits !== undefined) byTag[tagID].activeBits = sample.activeBits;
  if (sample.activeLabels !== undefined) byTag[tagID].activeLabels = sample.activeLabels;
  if (sample.rawValue !== undefined) byTag[tagID].rawValue = sample.rawValue;
}

store[equipmentName] = Object.values(byTag).sort((a, b) => a.tagID.localeCompare(b.tagID));
global.set('telemetry', store);
global.set('NEW_telemetry', store);

msg.payload = {
  equipment: equipmentName,
  count: store[equipmentName].length,
  NEW_telemetry: store[equipmentName]
};
return msg;

const requested = msg.equipmentId || msg.payload?.equipment || 'MBMU';
const store = global.get('NEW_telemetry') || global.get('telemetry') || {};
msg.payload = {
  equipment: requested,
  NEW_telemetry: Array.isArray(store[requested]) ? store[requested] : []
};
return msg;

const lib = global.get('lib');
if (!lib || !lib.telemetry || typeof lib.telemetry.buildSs40kLookup !== 'function') {
  node.status({ fill: 'red', shape: 'ring', text: 'ss40k API missing' });
  return { payload: { error: 'SS40K_API_MISSING' } };
}

const equipmentConfig = {
  PCS: { profileName: 'Delta_280_ss40k', route: 'PCS' },
  MBMU: { profileName: 'MBMU_280_ss40k', route: 'MBMU' },
  Meter: { profileName: 'eGauge_280_ss40k', route: 'METER' },
  Meter2: { profileName: 'eGauge_280_ss40k', route: 'METER' }
};

const result = lib.telemetry.buildSs40kLookup(equipmentConfig);

global.set('ss40kLookup', result.lookup);
global.set('ss40kEquipmentToProfile', result.equipmentToProfile);
global.set('ss40kModelIndexMap', result.modelIndexMap);
flow.set('telemetryRouteMap', result.routeMap);
flow.set('telemetryEquipmentConfig', equipmentConfig);

node.status({ fill: 'green', shape: 'dot', text: `${Object.keys(result.lookup).length} mapped tags` });
msg.payload = {
  lookupCount: Object.keys(result.lookup).length,
  equipmentToProfile: result.equipmentToProfile,
  routeMap: result.routeMap,
  modelIndexMap: result.modelIndexMap,
  sample: Object.fromEntries(Object.entries(result.lookup).slice(0, 10))
};
return msg;

const lib = global.get('lib');
if (!lib || !lib.telemetry || typeof lib.telemetry.buildSs40kFixedPayloads !== 'function') {
  node.status({ fill: 'red', shape: 'ring', text: 'ss40k API missing' });
  return [null, { payload: { error: 'SS40K_API_MISSING' } }, null];
}

const lookup = global.get('ss40kLookup') || {};
const telemetry = global.get('NEW_telemetry') || global.get('telemetry') || {};
if (!Object.keys(lookup).length) {
  node.status({ fill: 'yellow', shape: 'ring', text: 'lookup missing' });
  return [null, { payload: { error: 'SS40K_LOOKUP_MISSING' } }, null];
}

const messages = lib.telemetry.buildSs40kFixedPayloads({
  lookup,
  telemetry,
  topic: 'fort/v1/things/25000761/telem',
  version: '3.0'
});

node.status({ fill: 'green', shape: 'dot', text: `${messages.length} payloads` });
return [messages, null, { payload: messages.map((msg) => msg.ss40k) }];

msg.payload = {
  equipmentToProfile: global.get('ss40kEquipmentToProfile') || {},
  modelIndexMap: global.get('ss40kModelIndexMap') || {},
  lookup: global.get('ss40kLookup') || {}
};
return msg;

const routing = Object.assign({ MBMU: 'MBMU', PCS: 'PCS' }, flow.get('telemetryRouteMap') || {});
const routeKey = msg.serverKey || msg.equipmentId || msg._reader?.equipmentId;
const target = routeKey ? routing[routeKey] : null;
if (target === 'MBMU') return [msg, null, null];
if (target === 'PCS') return [null, msg, null];
node.status({ fill: 'yellow', shape: 'ring', text: `no route ${routeKey || '?'}` });
return [null, null, { payload: { error: 'NO_MODBUS_ROUTE', routeKey, routing } }];
